        <h1 className="text-white text-2xl font-black italic tracking-tighter">
          🚛 TRUCK LOAD BOARD
        </h1>
        <div className="bg-yellowMain text-redMain px-4 py-1 rounded-full font-bold">
          LTL Marketplace
        </div>
      </div>
    </nav>
  );
}
